class SparseTable {
    constructor(arr) {
        this.n = arr.length;
        this.log = new Array(this.n + 1).fill(0);
        this.st = [];
        this.build(arr);
    }

    build(arr) {
        for (let i = 0; (1 << i) <= this.n; i++) {
            this.st.push(new Array(this.n).fill(-Infinity));
        }

        for (let i = 0; i < this.n; i++) {
            this.st[0][i] = arr[i];
        }

        for (let j = 1; (1 << j) <= this.n; j++) {
            for (let i = 0; i + (1 << j) <= this.n; i++) {
                this.st[j][i] = Math.max(this.st[j-1][i], this.st[j-1][i + (1 << (j-1))]);
            }
        }

        for (let i = 2; i <= this.n; i++) {
            this.log[i] = this.log[i >> 1] + 1;
        }
    }

    query(l, r) {
        if (l > r) {
            return -Infinity;
        }
        let j = this.log[r - l + 1];
        return Math.max(this.st[j][l], this.st[j][r - (1 << j) + 1]);
    }
}

function solve(nums) {
    const n = nums.length;
    const INF = 1e18;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    const left_start = new Array(n).fill(0);
    const min_prefix_left = new Array(n).fill(0);
    const valid_left = new Array(n).fill(false);
    const min_prefix_left_strict = new Array(n).fill(INF);

    for (let i = 0; i < n; i++) {
        if (i === 0) {
            left_start[i] = 0;
            min_prefix_left[i] = prefix[0];
            valid_left[i] = false;
        } else {
            if (nums[i] > nums[i - 1]) {
                left_start[i] = left_start[i - 1];
                min_prefix_left[i] = Math.min(min_prefix_left[i - 1], prefix[i]);
                const length_seg = i - left_start[i] + 1;
                if (length_seg >= 2) {
                    valid_left[i] = true;
                    min_prefix_left_strict[i] = min_prefix_left[i - 1];
                } else {
                    valid_left[i] = false;
                }
            } else {
                left_start[i] = i;
                min_prefix_left[i] = prefix[i];
                valid_left[i] = false;
            }
        }
    }

    const right_end = new Array(n).fill(0);
    const max_prefix_right = new Array(n).fill(-INF);
    const valid_right = new Array(n).fill(false);
    const max_prefix_right_strict = new Array(n).fill(-INF);

    for (let i = n - 1; i >= 0; i--) {
        if (i === n - 1) {
            right_end[i] = i;
            max_prefix_right[i] = prefix[i + 1];
            valid_right[i] = false;
        } else {
            if (nums[i] < nums[i + 1]) {
                right_end[i] = right_end[i + 1];
                max_prefix_right[i] = Math.max(max_prefix_right[i + 1], prefix[i + 1]);
                max_prefix_right_strict[i] = max_prefix_right[i + 1];
                if (right_end[i] > i) {
                    valid_right[i] = true;
                } else {
                    valid_right[i] = false;
                }
            } else {
                right_end[i] = i;
                max_prefix_right[i] = prefix[i + 1];
                valid_right[i] = false;
            }
        }
    }

    const decreasing_length = new Array(n).fill(1);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            decreasing_length[i] = decreasing_length[i + 1] + 1;
        } else {
            decreasing_length[i] = 1;
        }
    }

    const A = new Array(n);
    for (let i = 0; i < n; i++) {
        if (valid_right[i]) {
            A[i] = max_prefix_right_strict[i];
        } else {
            A[i] = -INF;
        }
    }

    const sparseTable = new SparseTable(A);

    let ans = -INF;
    for (let p = 0; p < n; p++) {
        if (valid_left[p] && decreasing_length[p] >= 2) {
            const start = p + 1;
            const end = Math.min(p + decreasing_length[p] - 1, n - 1);
            if (start <= end) {
                const max_right_val = sparseTable.query(start, end);
                if (max_right_val > -INF / 2) {
                    const candidate = max_right_val - min_prefix_left_strict[p];
                    if (candidate > ans) {
                        ans = candidate;
                    }
                }
            }
        }
    }

    return ans;
}
